import xml.etree.ElementTree as ET
from xml.parsers.expat import ExpatError
import io

def validate_xml_file(file_content):
    """
    Validates an XML document from file content
    
    Args:
        file_content (str): XML content as string
        
    Returns:
        tuple: (is_valid, error_message)
    """
    try:
        # Parse the XML content
        root = ET.fromstring(file_content)
        return True, "XML is valid"
    except ET.ParseError as e:
        return False, f"XML Parse Error: {str(e)}"
    except ExpatError as e:
        return False, f"XML Expat Error: {str(e)}"
    except Exception as e:
        return False, f"Unexpected error: {str(e)}"

def validate_xml_upload(file_path=None, file_content=None):
    """
    Validates XML document from file path or content
    
    Args:
        file_path (str): Path to XML file
        file_content (str): XML content as string
        
    Returns:
        tuple: (is_valid, error_message)
    """
    try:
        if file_path:
            # Read from file
            with open(file_path, 'r', encoding='utf-8') as file:
                content = file.read()
        elif file_content:
            # Use provided content
            content = file_content
        else:
            return False, "No file content provided"
        
        # Validate XML
        return validate_xml_file(content)
        
    except FileNotFoundError:
        return False, "File not found"
    except PermissionError:
        return False, "Permission denied reading file"
    except UnicodeDecodeError:
        return False, "File encoding error"
    except Exception as e:
        return False, f"Error reading file: {str(e)}"